import 'package:flutter/material.dart';
import 'package:in_app_purchase/in_app_purchase.dart';
import 'package:http/http.dart' as http;
import 'dart:convert';

class PaymentService {
  final String _apiUrl = 'https://yourapi.com/payments';

  Future<void> initialize() async {
    final bool available = await InAppPurchase.instance.isAvailable();
    if (!available) {
      throw Exception('In-app purchases not available');
    }
  }

  Future<List<ProductDetails>> fetchProducts(List<String> productIds) async {
    final ProductDetailsResponse response = await InAppPurchase.instance.queryProductDetails(productIds.toSet());
    if (response.notFoundIDs.isNotEmpty) {
      throw Exception('Products not found: ${response.notFoundIDs}');
    }
    return response.productDetails;
  }

  Future<void> purchaseProduct(ProductDetails productDetails) async {
    final PurchaseParam purchaseParam = PurchaseParam(productDetails: productDetails);
    await InAppPurchase.instance.buyConsumable(purchaseParam: purchaseParam);
  }

  Future<void> verifyPurchase(PurchaseDetails purchaseDetails) async {
    final response = await http.post(
      Uri.parse(_apiUrl),
      headers: {'Content-Type': 'application/json'},
      body: jsonEncode({
        'transactionId': purchaseDetails.transactionId,
        'productId': purchaseDetails.productID,
        'userId': 'user_id_here', // Replace with actual user ID
      }),
    );

    if (response.statusCode != 200) {
      throw Exception('Failed to verify purchase: ${response.body}');
    }
  }
}

class PaymentScreen extends StatefulWidget {
  @override
  _PaymentScreenState createState() => _PaymentScreenState();
}

class _PaymentScreenState extends State<PaymentScreen> {
