  void _buyProduct(ProductDetails product) async {
    try {
      await _paymentService.purchaseProduct(product);
    } catch (e) {
      print('Error purchasing product: $e');
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
